import json
from datetime import datetime

# Read the full review data from the file
with open('var_functions.query_db:10', 'r') as f:
    reviews_2016 = json.load(f)

print('Total reviews in 2016:', len(reviews_2016))

# Parse dates and filter for Jan 1 - Jun 30, 2016
start_date = datetime(2016, 1, 1)
end_date = datetime(2016, 6, 30, 23, 59, 59)

filtered_reviews = []
for review in reviews_2016:
    try:
        date_str = review.get('date', '')
        if not date_str:
            continue

        # Try parsing different date formats
        date_obj = None
        try:
            # Try format: 2016-01-01 02:46:00
            if '2016-' in date_str:
                parts = date_str.split(' ')[0].split('-')
                if len(parts) == 3:
                    date_obj = datetime(2016, int(parts[1]), int(parts[2]))
            # Try format: 21 May 2016, 18:48
            elif '2016' in date_str and ('Jan' in date_str or 'Feb' in date_str or 'Mar' in date_str or 
                                        'Apr' in date_str or 'May' in date_str or 'Jun' in date_str):
                month_map = {'Jan': 1, 'Feb': 2, 'Mar': 3, 'Apr': 4, 'May': 5, 'Jun': 6}
                parts = date_str.split(' ')
                if len(parts) >= 2:
                    day = int(parts[0])
                    month_str = parts[1]
                    if month_str in month_map:
                        month = month_map[month_str]
                        date_obj = datetime(2016, month, day)
            # Try format: January 24, 2016 at 01:25 AM
            elif '2016 at' in date_str and ('January' in date_str or 'February' in date_str or 'March' in date_str or 
                                           'April' in date_str or 'May' in date_str or 'June' in date_str):
                month_map = {'January': 1, 'February': 2, 'March': 3, 'April': 4, 'May': 5, 'June': 6}
                parts = date_str.split(' ')
                if len(parts) >= 2:
                    month_str = parts[0]
                    day = int(parts[1].replace(',', ''))
                    if month_str in month_map:
                        month = month_map[month_str]
                        date_obj = datetime(2016, month, day)
        except:
            pass

        if date_obj and start_date <= date_obj <= end_date:
            filtered_reviews.append({
                'business_ref': review['business_ref'],
                'rating': int(review['rating'])
            })
    except:
        continue

print('Reviews in date range (Jan 1 - Jun 30, 2016):', len(filtered_reviews))

# Group by business_ref and calculate stats
business_stats = {}
for r in filtered_reviews:
    biz_ref = r['business_ref']
    if biz_ref not in business_stats:
        business_stats[biz_ref] = {'total_rating': 0, 'count': 0}
    business_stats[biz_ref]['total_rating'] += r['rating']
    business_stats[biz_ref]['count'] += 1

# Calculate averages for businesses with at least 5 reviews
business_averages = []
for biz_ref, stats in business_stats.items():
    if stats['count'] >= 5:
        avg_rating = stats['total_rating'] / stats['count']
        business_averages.append({
            'business_ref': biz_ref,
            'avg_rating': avg_rating,
            'review_count': stats['count']
        })

print('Businesses with >= 5 reviews:', len(business_averages))

# Sort by average rating descending
business_averages.sort(key=lambda x: x['avg_rating'], reverse=True)

if business_averages:
    print('Top business:', business_averages[0])
else:
    print('No businesses found with >= 5 reviews')

result = {
    'business_averages': business_averages
}

print('\n__RESULT__:')
print(json.dumps(result))

